// Generated by hand. Sets up the shared Wiki vault in Obsidian — the
// always-on knowledge base for clients, systems, processes, and roles.
// Safe to re-run: it only creates what's missing, never overwrites notes.

import { promises as fs } from 'node:fs';
import path from 'node:path';

export const definition = {
  id: 'obsidian-wiki',
  name: 'Obsidian Wiki Setup',
  description:
    "Builds the folder structure for your Wiki vault in Obsidian — a place to keep notes about clients, systems, processes, and roles, organized so you (and Claude) can always find things. Point it at any folder; existing files are left alone, only missing pieces are added.",
  version: '1.0.0',
  inputs: [
    {
      name: 'vaultPath',
      type: 'text',
      label: 'Wiki vault folder',
      description: 'Full path to the folder you open as your Wiki vault in Obsidian. Can be a brand-new empty folder or one you already use.',
      required: true,
    },
    {
      name: 'dryRun',
      type: 'boolean',
      label: 'Preview only (don’t create anything yet)',
      description: 'Check this to see what would be created without touching your files.',
      required: false,
    },
  ],
};

const FOLDERS = ['clients', 'systems', 'processes', 'roles', 'prompts', 'unsorted', 'archive'];

const README = `# Wiki Vault

This is your knowledge base — notes about clients, systems, processes, and roles.

- **clients/**, **systems/**, **processes/**, **roles/** — your organized knowledge, grouped by what it's about.
- **prompts/** — reusable instructions you've written, linked back to the notes that use them.
- **unsorted/** — quick captures that haven't been filed yet.
- **archive/** — retired notes you don't need active, but don't want to delete.

This vault is always available to Claude for answering questions grounded in what you've actually written here.
`;

export async function run(input, _ctx) {
  const vaultPath = String(input.vaultPath || '').trim();
  if (!vaultPath) return { ok: false, error: 'vaultPath is required' };
  const dryRun = !!input.dryRun;

  const created = [];
  const alreadyExisted = [];

  for (const folder of FOLDERS) {
    const dir = path.join(vaultPath, folder);
    if (dryRun) {
      created.push(dir);
      continue;
    }
    let existed = true;
    try {
      await fs.access(dir);
    } catch {
      existed = false;
    }
    await fs.mkdir(dir, { recursive: true });
    (existed ? alreadyExisted : created).push(dir);
  }

  const readmePath = path.join(vaultPath, 'README.md');
  let readmeWritten = false;
  if (dryRun) {
    readmeWritten = true;
  } else {
    try {
      await fs.access(readmePath);
    } catch {
      await fs.writeFile(readmePath, README, 'utf8');
      readmeWritten = true;
    }
  }

  return {
    ok: true,
    dryRun,
    vaultPath,
    foldersPlanned: FOLDERS,
    created,
    alreadyExisted,
    readmeWritten,
  };
}

export const tests = [
  {
    name: 'dry run reports planned folders without touching disk',
    input: { vaultPath: 'C:/Example/WikiVault', dryRun: true },
    expect: {
      ok: true,
      dryRun: true,
      vaultPath: 'C:/Example/WikiVault',
      foldersPlanned: ['clients', 'systems', 'processes', 'roles', 'prompts', 'unsorted', 'archive'],
      created: [
        'C:\\Example\\WikiVault\\clients',
        'C:\\Example\\WikiVault\\systems',
        'C:\\Example\\WikiVault\\processes',
        'C:\\Example\\WikiVault\\roles',
        'C:\\Example\\WikiVault\\prompts',
        'C:\\Example\\WikiVault\\unsorted',
        'C:\\Example\\WikiVault\\archive',
      ],
      alreadyExisted: [],
      readmeWritten: true,
    },
  },
  {
    name: 'missing vaultPath fails fast',
    input: {},
    expect: { ok: false, error: 'vaultPath is required' },
  },
];
